import functools
import weakref

def detect_flakiness(func, iterations=10):
    results = []
    for _ in range(iterations):
        try:
            result = func()
            if result is None:
                results.append(None)
                continue
            attempts = 0
            while attempts < iterations - 1:
                try:
                    func()
                except Exception as e:
                    # If the error type remains consistent, return True
                    if str(e) in results:
                        return True
                attempts += 1
        except Exception as e:
            # If the error type remains consistent, return True
            if str(e) in results:
                return True

        results.append(result)

    # If all results are the same, return False
    return len(set(results)) == 1
