def detect_flakiness(func, iterations=10):
    results = []
    error_types = set()

    for _ in range(iterations):
        try:
            result = func()
            results.append(result)
        except Exception as e:
            error_types.add(type(e))

    # If the return values are consistent, return False
    if len(set(results)) == 1:
        return False

    # If the error is always raised, return False
    if len(error_types) == 1:
        return False

    return True

# Test the function
def test_flakiness():
    def stable_err():
        raise Exception("Error")
    def stable_val():
        return 1
    def unstable_func():
        return 1
    def unstable_func2():
        return 2

    assert detect_flakiness(stable_err) == False
    assert detect_flakiness(stable_val) == False
    assert detect_flakiness(unstable_func) == True
    assert detect_flakiness(unstable_func2) == True

test_flakiness()
